import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.Dn0B0GT3.js";const u=JSON.parse('{"title":"TOTP 2FA","description":"Set up and use TOTP two-factor authentication with ShellPort","frontmatter":{"title":"TOTP 2FA","description":"Set up and use TOTP two-factor authentication with ShellPort"},"headers":[],"relativePath":"guides/totp.md","filePath":"guides/totp.md"}'),n={name:"guides/totp.md"};function o(r,e,l,p,d,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="totp-2fa" tabindex="-1">TOTP 2FA <a class="header-anchor" href="#totp-2fa" aria-label="Permalink to &quot;TOTP 2FA&quot;">​</a></h1><p>ShellPort supports RFC 6238 Time-based One-Time Password (TOTP) two-factor authentication. This adds an extra layer of security by requiring both your encryption secret and a time-based code from your authenticator app.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When TOTP is enabled:</p><ol><li>On first run, ShellPort generates a unique pairing secret</li><li>A QR code is displayed in your terminal for easy pairing</li><li>You scan the QR code with any TOTP-compatible app</li><li>On each connection, you&#39;ll need both the URL secret and a 6-digit TOTP code</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Any TOTP-compatible authenticator app: <ul><li><strong>Authenticator</strong> (iOS/Android)</li><li><strong>Google Authenticator</strong> (iOS/Android)</li><li><strong>Authy</strong> (iOS/Android/Desktop)</li><li><strong>1Password</strong> (includes built-in authenticator)</li><li><strong>Bitwarden</strong> (includes built-in authenticator)</li></ul></li></ul><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><h3 id="_1-start-shellport" tabindex="-1">1. Start ShellPort <a class="header-anchor" href="#_1-start-shellport" aria-label="Permalink to &quot;1. Start ShellPort&quot;">​</a></h3><p>Run the server with TOTP enabled (default):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span></span></code></pre></div><h3 id="_2-scan-the-qr-code" tabindex="-1">2. Scan the QR Code <a class="header-anchor" href="#_2-scan-the-qr-code" aria-label="Permalink to &quot;2. Scan the QR Code&quot;">​</a></h3><p>On first run, you&#39;ll see a QR code rendered directly in your terminal:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ShellPort] 🔐 TOTP 2FA is enabled</span></span>
<span class="line"><span>[ShellPort]    Algorithm: SHA1 | Digits: 6 | Period: 30s</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    ████████████████████████████████</span></span>
<span class="line"><span>    ██                          ██</span></span>
<span class="line"><span>    ██  ████████  ████████      ██</span></span>
<span class="line"><span>    ██  ████████  ████████      ██</span></span>
<span class="line"><span>    ██  ████████  ████████      ██</span></span>
<span class="line"><span>    ██  ████████  ████████      ██</span></span>
<span class="line"><span>    ██                          ██</span></span>
<span class="line"><span>    ████████████████████████████████</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[ShellPort] Open any authenticator app and scan the QR code above</span></span></code></pre></div><h3 id="_3-pair-your-app" tabindex="-1">3. Pair Your App <a class="header-anchor" href="#_3-pair-your-app" aria-label="Permalink to &quot;3. Pair Your App&quot;">​</a></h3><p>Open your authenticator app and scan the QR code using its built-in scanner. The app will add &quot;ShellPort&quot; to your list of accounts.</p><h3 id="_4-enter-the-code" tabindex="-1">4. Enter the Code <a class="header-anchor" href="#_4-enter-the-code" aria-label="Permalink to &quot;4. Enter the Code&quot;">​</a></h3><p>When connecting, you&#39;ll be prompted for the 6-digit code from your authenticator:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ShellPort] 🔐 Enter TOTP code: _</span></span></code></pre></div><p>Enter the code currently displayed in your authenticator app (it changes every 30 seconds).</p><h2 id="persistent-pairing" tabindex="-1">Persistent Pairing <a class="header-anchor" href="#persistent-pairing" aria-label="Permalink to &quot;Persistent Pairing&quot;">​</a></h2><p>Once paired, your TOTP secret is saved to <code>~/.shellport-totp-secret</code>. This means:</p><ul><li>✅ You only need to scan the QR code once</li><li>✅ The secret persists across server restarts</li><li>✅ You can connect from any browser with your authenticator</li></ul><h2 id="resetting-totp" tabindex="-1">Resetting TOTP <a class="header-anchor" href="#resetting-totp" aria-label="Permalink to &quot;Resetting TOTP&quot;">​</a></h2><p>If you need to re-pair (new phone, authenticator reset, etc.), use the <code>--totp-reset</code> flag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --totp-reset</span></span></code></pre></div><p>This will:</p><ol><li>Delete the existing TOTP secret from <code>~/.shellport-totp-secret</code></li><li>Generate a new pairing secret on next startup</li><li>Display a new QR code for re-pairing</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ShellPort] 🔄 TOTP secret reset. A new pairing will be generated.</span></span></code></pre></div><h2 id="disabling-totp" tabindex="-1">Disabling TOTP <a class="header-anchor" href="#disabling-totp" aria-label="Permalink to &quot;Disabling TOTP&quot;">​</a></h2><p>If you prefer to run without TOTP (e.g., on a trusted network):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span></span></code></pre></div><p>This disables TOTP authentication while keeping encryption enabled.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For trusted networks like your home LAN or corporate VPN, <code>--no-totp</code> provides a good balance of security (encryption) and convenience (no 2FA).</p></div><h2 id="totp-without-encryption" tabindex="-1">TOTP Without Encryption <a class="header-anchor" href="#totp-without-encryption" aria-label="Permalink to &quot;TOTP Without Encryption&quot;">​</a></h2><p>You can also run with TOTP but no encryption:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span></span></code></pre></div><p>This is useful when connected via Tailscale or WireGuard, where the VPN provides network-level encryption.</p><h2 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to &quot;Technical Details&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Standard</td><td>RFC 6238</td></tr><tr><td>Algorithm</td><td>SHA-1</td></tr><tr><td>Digits</td><td>6</td></tr><tr><td>Period</td><td>30 seconds</td></tr><tr><td>Secret Storage</td><td><code>~/.shellport-totp-secret</code></td></tr><tr><td>Compatibility</td><td>Google Authenticator, Authy, 1Password, Bitwarden</td></tr></tbody></table><h2 id="security-notes" tabindex="-1">Security Notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security Notes&quot;">​</a></h2><ul><li>The TOTP secret is stored in plain text in <code>~/.shellport-totp-secret</code></li><li>Protect this file appropriately for your security model</li><li>If <code>--quiet</code> is used, the secret loading message is suppressed</li><li>TOTP adds significant security but is not foolproof against all attacks</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="qr-code-not-scanning" tabindex="-1">QR Code Not Scanning <a class="header-anchor" href="#qr-code-not-scanning" aria-label="Permalink to &quot;QR Code Not Scanning&quot;">​</a></h3><ul><li>Ensure your authenticator app can scan QR codes (most can)</li><li>If using 1Password or Bitwarden, use the built-in &quot;Scan QR Code&quot; option</li><li>For command-line tools like <code>oathtool</code>, you can manually enter the secret</li></ul><h3 id="code-rejected" tabindex="-1">Code Rejected <a class="header-anchor" href="#code-rejected" aria-label="Permalink to &quot;Code Rejected&quot;">​</a></h3><ul><li>Ensure your device&#39;s time is accurate (TOTP is time-based)</li><li>Try the next code (codes are valid for one period before and after)</li><li>Use <code>--totp-reset</code> to generate a new pairing</li></ul><h3 id="secret-file-missing" tabindex="-1">Secret File Missing <a class="header-anchor" href="#secret-file-missing" aria-label="Permalink to &quot;Secret File Missing&quot;">​</a></h3><p>If <code>~/.shellport-totp-secret</code> is accidentally deleted, simply run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --totp-reset</span></span></code></pre></div><p>to generate a new pairing secret and QR code.</p>`,51)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
